        double score = 0.0;

        for (int j = 0; j < S.stack_size[d]; j++) {
            int box_in_dest = S.stacks[d][j];
            if (box_in_dest > urgent_box && box_in_dest < urgent_box + 20) {
                int boxes_above_after = (S.stack_size[d] - 1 - j) + num_boxes_in_bottom;
                double urgency = 20.0 / (box_in_dest - urgent_box);
                score += urgency * boxes_above_after * 0.8;
            }
        }

        if (S.stack_size[d] == 0) score += 80.0;
        score += S.stack_size[d] * 0.5;

        if (num_boxes_in_bottom == 1) {
            score -= 20.0;
        }

        if (score < best_score) { best_score = score; best_dest = d; }
    }
    return best_dest;
}

// Simulate with optional block splitting
// plan is 2*N: plan[2k] = primary dest, plan[2k+1] = split dest
// Split triggers when plan[2k] != plan[2k+1] and there's a beneficial split opportunity
long long simulate_split(const std::vector<std::vector<int>>& initial_stacks,
                         const int* plan, int N, int M) {
    State S;
    S.init(N, M, initial_stacks);

    for (int k = 0; k < N; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;

        if (num_on_top > 0) {
            int dest1 = plan[2 * k];
            int dest2 = plan[2 * k + 1];
            if (dest1 == src) dest1 = (src + 1) % M;
            if (dest2 == src) dest2 = (src + 1) % M;

            bool do_split = false;
            int split_pos = -1; // position in stack of the urgent box

            if (dest1 != dest2 && num_on_top >= 3) {
                int best_urgent = -1;
                int best_pos = -1;
                int best_depth = 0; // how many boxes above it

                for (int p = h + 1; p <= h + num_on_top; p++) {
                    int box = S.stacks[src][p];
                    if (box > k && box < k + 8) {
                        int depth_above = (h + num_on_top) - p;
                        if (depth_above >= 2) {
                            if (best_urgent == -1 || box < best_urgent) {
                                best_urgent = box;
                                best_pos = p;
                                best_depth = depth_above;
                            }
                        }
                    }
                }

                if (best_urgent >= 0 && best_depth >= 2) {
                    do_split = true;
                    split_pos = best_pos;
                }
            }

            if (do_split) {
                // Move top portion (above split_pos) to dest1
                int top_count = (h + num_on_top) - split_pos;
                int first_top = S.stacks[src][split_pos + 1];
                S.move_block(first_top, top_count, dest1);

                // Move bottom portion (h+1 to split_pos, urgent on top) to dest2
                int bottom_count = split_pos - h;
                int first_bottom = S.stacks[src][h + 1];
                S.move_block(first_bottom, bottom_count, dest2);
            } else {
                // Single move all to dest1
                int first_box = S.stacks[src][h + 1];
                S.move_block(first_box, num_on_top, dest1);
            }
        }
        S.carry_out(k);
    }
    return S.energy;
}

long long lookahead_energy(State S, int start_k, int W) {
    long long e0 = S.energy;
    int end_k = std::min(start_k + W, S.N);
    for (int k = start_k; k < end_k; k++) {
        int src = S.box_stack[k];
        int h = S.box_height[k];
        int num_on_top = S.stack_size[src] - 1 - h;
        if (num_on_top > 0) {
            int dest = greedy_best_dest(S, k);
            if (dest == src) dest = (src + 1) % S.M;
            S.move_block(S.stacks[src][h + 1], num_on_top, dest);
        }
        S.carry_out(k);
    }
    return S.energy - e0;
}

void beam_search(const std::vector<std::vector<int>>& initial_stacks,
                 int N, int M, int* result_plan, double time_limit) {
    const int BEAM_W = 12;
    const int LOOKAHEAD = 8;

    struct BeamNode {
        State state;
        int plan[MAX_N * 2]; // 2*N: plan[2k]=dest1, plan[2k+1]=dest2
    };

    std::vector<BeamNode> beam(1);
    beam[0].state.init(N, M, initial_stacks);
    beam.reserve(BEAM_W);

    std::vector<BeamNode> candidates;
    candidates.reserve(BEAM_W * (M - 1) + BEAM_W);

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_limit) {
            auto& best = beam[0];
            for (int kk = k; kk < N; kk++) {
                int d = greedy_best_dest(best.state, kk);
                best.plan[2 * kk] = d;
                best.plan[2 * kk + 1] = d; // no split by default
                int src = best.state.box_stack[kk];
                int h = best.state.box_height[kk];
                int num_on_top = best.state.stack_size[src] - 1 - h;
                if (num_on_top > 0) {
                    int dest = d;
                    if (dest == src) dest = (src + 1) % M;
                    best.state.move_block(best.state.stacks[src][h + 1], num_on_top, dest);
                }
                best.state.carry_out(kk);
            }
            memcpy(result_plan, best.plan, sizeof(int) * N * 2);
            return;
        }

        candidates.clear();

        for (auto& node : beam) {
            int src = node.state.box_stack[k];
            int h = node.state.box_height[k];
            int num_on_top = node.state.stack_size[src] - 1 - h;

            if (num_on_top == 0) {
                candidates.push_back(node);
                auto& cand = candidates.back();
                cand.plan[2 * k] = src;
                cand.plan[2 * k + 1] = src;
                cand.state.carry_out(k);
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    candidates.push_back(node);
                    auto& cand = candidates.back();
                    cand.plan[2 * k] = d;
                    cand.plan[2 * k + 1] = d; // beam search doesn't split
                    cand.state.move_block(cand.state.stacks[src][h + 1], num_on_top, d);
                    cand.state.carry_out(k);
                }
            }
        }

        if (candidates.empty()) break;

        std::vector<std::pair<long long, int>> scores(candidates.size());
        for (int i = 0; i < (int)candidates.size(); i++) {
            long long future = lookahead_energy(candidates[i].state, k + 1, LOOKAHEAD);
            scores[i] = {candidates[i].state.energy + future, i};
        }
        std::sort(scores.begin(), scores.end());

        beam.clear();
        int width = std::min(BEAM_W, (int)scores.size());
        for (int i = 0; i < width; i++) {
            beam.push_back(std::move(candidates[scores[i].second]));
        }
    }

    int best_idx = 0;
    for (int i = 1; i < (int)beam.size(); i++) {
        if (beam[i].state.energy < beam[best_idx].state.energy) best_idx = i;
    }
    memcpy(result_plan, beam[best_idx].plan, sizeof(int) * N * 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();
    RGen.seed_time();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> initial_stacks(M);
    for (int i = 0; i < M; i++) {
        initial_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> initial_stacks[i][j];
        }
    }

    // Phase 1: Beam search for initial plan (0.4s)
    int best_plan[MAX_N * 2];
    beam_search(initial_stacks, N, M, best_plan, 0.40);
    long long best_energy = simulate_split(initial_stacks, best_plan, N, M);

    // Phase 2: SA refinement on 2*N plan
    int current_plan[MAX_N * 2];
    memcpy(current_plan, best_plan, sizeof(int) * N * 2);
    long long current_energy = best_energy;

    const double SA_END_TIME = 1.75;
    double sa_start = elapsed_seconds();
    double sa_budget = SA_END_TIME - sa_start;
    double T_init = 8.0;
    double T_final = 0.5;
    double current_T = T_init;

    while (true) {
        double now = elapsed_seconds();
        if (now >= SA_END_TIME) break;
        double progress = (now - sa_start) / sa_budget;
        current_T = T_init * std::pow(T_final / T_init, std::min(1.0, progress));

        for (int batch = 0; batch < 256; batch++) {
            // Bias toward earlier indices (quadratic distribution on box index)
            int box_idx = std::min(N - 1, (int)(N * (1.0 - std::sqrt(RGen.a_double(0, 1)))));

            // Decide whether to mutate primary dest or split dest
            int plan_idx;
            if (RGen.an_int(0, 2) == 0) {
                plan_idx = 2 * box_idx + 1; // mutate split dest
            } else {
                plan_idx = 2 * box_idx; // mutate primary dest
            }

            int old_val = current_plan[plan_idx];
            current_plan[plan_idx] = RGen.an_int(0, M - 1);

            // Optionally also mutate the adjacent entry (2-point)
            int plan_idx2 = -1;
            int old_val2 = 0;
            if (RGen.an_int(0, 9) < 2 && box_idx + 1 < N) {
                plan_idx2 = 2 * (box_idx + 1) + RGen.an_int(0, 1);
                old_val2 = current_plan[plan_idx2];
                current_plan[plan_idx2] = RGen.an_int(0, M - 1);
            }

            long long new_energy = simulate_split(initial_stacks, current_plan, N, M);

            long long delta = new_energy - current_energy;
            if (delta <= 0 || RGen.a_double(0, 1) < std::exp(-(double)delta / current_T)) {
                current_energy = new_energy;
                if (new_energy < best_energy) {
                    best_energy = new_energy;
                    memcpy(best_plan, current_plan, sizeof(int) * N * 2);
                }
            } else {
                current_plan[plan_idx] = old_val;
                if (plan_idx2 >= 0) current_plan[plan_idx2] = old_val2;
            }
        }
    }

    // Output using best_plan with splitting
    {
        State S;
        S.init(N, M, initial_stacks);
        for (int k = 0; k < N; k++) {
            int src = S.box_stack[k];
            int h = S.box_height[k];
            int num_on_top = S.stack_size[src] - 1 - h;

            if (num_on_top > 0) {
                int dest1 = best_plan[2 * k];
                int dest2 = best_plan[2 * k + 1];
                if (dest1 == src) dest1 = (src + 1) % M;
                if (dest2 == src) dest2 = (src + 1) % M;

                bool do_split = false;
                int split_pos = -1;

                if (dest1 != dest2 && num_on_top >= 3) {
                    int best_urgent = -1;
                    int best_pos = -1;
                    int best_depth = 0;

                    for (int p = h + 1; p <= h + num_on_top; p++) {
                        int box = S.stacks[src][p];
                        if (box > k && box < k + 8) {
                            int depth_above = (h + num_on_top) - p;
                            if (depth_above >= 2) {
                                if (best_urgent == -1 || box < best_urgent) {
                                    best_urgent = box;
                                    best_pos = p;
                                    best_depth = depth_above;
                                }
                            }
                        }
                    }

                    if (best_urgent >= 0 && best_depth >= 2) {
                        do_split = true;
                        split_pos = best_pos;
                    }
                }

                if (do_split) {
                    // Move top portion to dest1
                    int top_count = (h + num_on_top) - split_pos;
                    int first_top = S.stacks[src][split_pos + 1];
                    std::cout << (first_top + 1) << " " << (dest1 + 1) << "\n";
                    S.move_block(first_top, top_count, dest1);

                    // Move bottom portion to dest2
                    int bottom_count = split_pos - h;
                    int first_bottom = S.stacks[src][h + 1];
                    std::cout << (first_bottom + 1) << " " << (dest2 + 1) << "\n";
                    S.move_block(first_bottom, bottom_count, dest2);
                } else {
                    int dest = dest1;
                    int first_box = S.stacks[src][h + 1];
                    std::cout << (first_box + 1) << " " << (dest + 1) << "\n";
                    S.move_block(first_box, num_on_top, dest);
                }
            }
            std::cout << (k + 1) << " 0\n";
            S.carry_out(k);
        }
    }

    return 0;
}
